from typing import Dict, Any
import yaml

def _load_yaml(path: Path) -> Dict[str, Any]:
    base_dir = Path('/safe/config/directory').resolve()
    abs_path = path.resolve()
    if not str(abs_path).startswith(str(base_dir)):
        raise ValueError("Access to the specified path is not allowed.")
    with open(abs_path, "r", encoding="utf-8") as f:
        return yaml.safe_load(f) or {}

def _find_all_tasks(tasks_dir: Path) -> List[Path]:
    if not tasks_dir.is_dir():
        raise ValueError(f"Invalid tasks_dir path: {tasks_dir}")
    base_path = tasks_dir.resolve()
    tasks = []
    for path in base_path.rglob("*.yaml"):
        # 确保所有匹配文件都在 base_path 下，避免路径遍历
        try:
            if base_path in path.resolve().parents or base_path == path.resolve():
                tasks.append(path)
        except RuntimeError:
            # 处理符号链接循环等异常，忽略此路径
            continue
    return sorted(tasks)

