def _normalize_date_input(d: Optional[Union[datetime, date_cls]], tz) -> date_cls:
    """
    Interpret provided date in the given timezone for correct solar day.
    """
    if d is None:
        # Today's date in tz
        if tz is None:
            return datetime.now(timezone.utc).astimezone(timezone.utc).date()
        now = datetime.now(tz)
        return now.date()
    if isinstance(d, datetime):
        if d.tzinfo is None:
            # Treat as naive in tz
            if tz is not None:
                d = d.replace(tzinfo=tz)
            else:
                d = d.replace(tzinfo=timezone.utc)
        if tz is not None:
            d = d.astimezone(tz)
        else:
            d = d.astimezone(timezone.utc)
        return d.date()
    # It's a date
    return d

